import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"Установлення Java на macOS","description":"Покрокова інструкція щодо встановлення Java на macOS.","frontmatter":{"title":"Установлення Java на macOS","description":"Покрокова інструкція щодо встановлення Java на macOS.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"uk_ua/players/installing-java/macos.md","filePath":"translated/uk_ua/players/installing-java/macos.md","lastUpdated":1774518827000}`);var c={name:`uk_ua/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установлення Java на macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Установлення Java на macOS”">​</a></h1><p>Цей посібник допоможе вам установити Java 21 на macOS.</p><p>Запускач Minecraft постачається з власною інсталяцією Java, тому цей розділ актуальний, лише якщо ви хочете використовувати встановлювач на основі Fabric <code>.jar</code> або якщо ви хочете використовувати сервер Minecraft <code>.jar</code>.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Перевірте, чи Java уже встановлено <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Перевірте, чи Java уже встановлено”">​</a></h2><p>У терміналі (розташованому в <code>/Applications/Utilities/Terminal.app</code>) введіть наступне та натисніть <kbd>Enter</kbd>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Ви повинні побачити щось на зразок наступного:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Зверніть увагу на номер версії: у наведеному вище прикладі це <code>21.0.9</code>.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Щоб використовувати Minecraft 1.21.11, вам потрібно встановити принаймні Java 21.</p><p>Якщо ця команда показує будь-яку версію, нижчу за 21, вам потрібно буде оновити наявну інсталяцію Java; продовжуйте читати цю сторінку.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Завантажте встановлювач Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Завантажте встановлювач Java 21”">​</a></h2><p>Ми рекомендуємо використовувати <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">збірку OpenJDK 21 від Adoptium</a>:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Сторінка завантаження Temurin Java" loading="lazy"></p><p>Переконайтеся, що вибрано версію «21 — LTS» і виберіть формат установлювача <code>.PKG</code>. Ви також повинні вибрати правильну архітектуру залежно від архітектури вашої системи:</p><ul><li>Якщо у вас чип Apple серії M, виберіть <code>aarch64</code> (усталений)</li><li>Якщо у вас чип Intel, виберіть <code>x64</code></li><li>Виконайте ці <a href="https://support.apple.com/uk-ua/116943" target="_blank" rel="noreferrer">інструкції, щоб дізнатися, який чип встановлено у вашому Mac</a></li></ul><p>Після завантаження встановлювача <code>.pkg</code> відкрийте його та дотримуйтеся вказівок:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Установлювач Temurin Java" loading="lazy"></p><p>Вам потрібно буде ввести пароль адміністратора, щоб завершити встановлення:</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="Запит пароля macOS" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Використання Homebrew <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Використання Homebrew”">​</a></h3><p>Якщо у вас уже встановлено <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>, ви можете встановити Java 21 за допомогою <code>brew</code>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Перевірте, чи встановлено Java 21 <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Перевірте, чи встановлено Java 21”">​</a></h2><p>Після завершення встановлення ви можете переконатися, що Java 21 активна, знову відкривши термінал і ввівши <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code>.</p><p>Якщо команда виконана успішно, ви повинні побачити щось на зразок цього:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Якщо у вас виникнуть проблеми, не соромтеся звертатися по допомогу до <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> на каналі <code>#player-support</code>.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};